1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const ITEM_BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
13	const COMPONENT_BLOCK_SIZE = 3;
14	const COMPONENT_BLOCK_PREMIUM = 60;
15	
16	type Item = { type: string };
17	type QuoteStep = { op: "quote"; items: Item[] };
18	type Step = QuoteStep;
19	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
20	
21	const isComponent = (type: string): boolean => COMPONENT_TYPES.has(type);
22	
23	const groupedBasePremium = (type: string, count: number): number => {
24	  if (isComponent(type) && count === COMPONENT_BLOCK_SIZE) {
25	    return COMPONENT_BLOCK_PREMIUM;
26	  }
27	  return count * ITEM_BASE_PREMIUM[type];
28	};
29	
30	const countByType = (items: Item[]): Map<string, number> => {
31	  const counts = new Map<string, number>();
32	  for (const item of items) {
33	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
34	  }
35	  return counts;
36	};
37	
38	const sumBasePremiums = (items: Item[]): number => {
39	  let total = 0;
40	  for (const [type, count] of countByType(items)) {
41	    total += groupedBasePremium(type, count);
42	  }
43	  return total;
44	};
45	
46	const quotePremium = (items: Item[]): number => {
47	  const basePremium = sumBasePremiums(items);
48	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
49	  const insurancePremium = Math.ceil(basePremium + firstInsuranceSurcharge);
50	  return insurancePremium + PROCESSING_FEE;
51	};
52	
53	const runStep = (step: Step) => ({ premium: quotePremium(step.items) });
54	
55	export const runScenario = (scenario: Scenario): unknown => ({
56	  results: scenario.steps.map(runStep),
57	});
